#!/usr/bin/env node
/**
 * start-local-with-mock.js
 *
 * Platform-independent script for running the frontend locally with mocked backend, generated by copilot.
 *
 * Usage:
 *    cd frontend                                                                                                                                                                                                                                                                                                                               ┃
 *    yarn install                                                                                                                                                                                                                                                                                                                              ┃
 *    node start-local-with-mock.js
 *
 * On start:
 *   - Writes .env from env.dev + PROXY_URL (required by vite.config.ts proxy)
 *   - Patches src/index.tsx to add: import('./mocks/mockFetch');
 *   - Starts the Vite dev server (yarn start)
 *
 * On exit (Ctrl+C or normal exit):
 *   - Reverts src/index.tsx to its original content
 *
 * Usage: node start-local-with-mock.js [--proxy-url <url>]
 */

const fs = require("fs");
const path = require("path");
const { spawn } = require("child_process");

// --- Config ---
const args = process.argv.slice(2);
const proxyUrlFlag = args.indexOf("--proxy-url");
const PROXY_URL =
  proxyUrlFlag !== -1 ? args[proxyUrlFlag + 1] : "http://localhost:8080";

const MOCK_IMPORT_COMMENT =
  "// Mocking av backend ved kjøring lokalt (DO NOT COMMIT THIS!!):";
const MOCK_IMPORT_LINE = "import('./mocks/mockFetch');";
const MOCK_BLOCK = `\n${MOCK_IMPORT_COMMENT}\n${MOCK_IMPORT_LINE}\n`;

const envDevPath = path.join(__dirname, "env.dev");
const envPath = path.join(__dirname, ".env");
const indexPath = path.join(__dirname, "src", "index.tsx");

// --- Patch .env ---
const envDevContent = fs.readFileSync(envDevPath, "utf8").trimEnd();
const envContent = `${envDevContent}\nPROXY_URL=${PROXY_URL}\n`;
fs.writeFileSync(envPath, envContent, "utf8");
console.log(`[mock-start] Wrote .env with PROXY_URL=${PROXY_URL}`);

// --- Patch index.tsx ---
const originalIndex = fs.readFileSync(indexPath, "utf8");
let patchedIndex = originalIndex;

if (!patchedIndex.includes(MOCK_IMPORT_LINE)) {
  // Insert mock import after the last top-level import statement
  const lastImportMatch = [...patchedIndex.matchAll(/^import .+;$/gm)].pop();
  if (lastImportMatch) {
    const insertAt = lastImportMatch.index + lastImportMatch[0].length;
    patchedIndex =
      patchedIndex.slice(0, insertAt) +
      MOCK_BLOCK +
      patchedIndex.slice(insertAt);
  } else {
    patchedIndex = MOCK_BLOCK + patchedIndex;
  }
  fs.writeFileSync(indexPath, patchedIndex, "utf8");
  console.log("[mock-start] Patched src/index.tsx with mock import");
} else {
  console.log(
    "[mock-start] src/index.tsx already contains mock import, skipping patch"
  );
}

// --- Cleanup on exit ---
function cleanup() {
  try {
    const current = fs.readFileSync(indexPath, "utf8");
    if (current !== originalIndex) {
      fs.writeFileSync(indexPath, originalIndex, "utf8");
      console.log("\n[mock-start] Reverted src/index.tsx");
    }
  } catch (e) {
    console.error("[mock-start] Failed to revert src/index.tsx:", e.message);
  }
  process.exit(0);
}

process.on("SIGINT", cleanup);
process.on("SIGTERM", cleanup);

// --- Start Vite ---
const isWindows = process.platform === "win32";

const child = spawn("yarn", ["start"], {
  stdio: "inherit",
  shell: isWindows,
  env: { ...process.env, PROXY_URL: PROXY_URL },
});

child.on("exit", (code) => {
  cleanup();
});
